#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, A, K;
        scanf("%d %d %d", &N, &A, &K);
        int d = (180 * (N - 2) - N * A) / (N * (N - 1) / 2);
        int num = A + (K - 1) * d;
        int g = gcd(num, 1);
        printf("%d %d\n", num / g, 1);
    }
    return 0;
}

