import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int A = sc.nextInt();
            int K = sc.nextInt();
            int d = (180 * (N - 2) - N * A) / (N * (N - 1) / 2);
            int num = A + (K - 1) * d;
            int g = gcd(num, 1);
            System.out.println(num / g + " " + 1);
        }
    }

    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}

