const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function gcd(a, b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

function main() {
    let T = +lines[idx++];
    while (T-- > 0) {
        let [N, A, K] = lines[idx++].split(' ').map(x => +x);
        let d = Math.floor((180 * (N - 2) - N * A) / (N * (N - 1) / 2));
        let num = A + (K - 1) * d;
        let g = gcd(num, 1);
        console.log(num / g + ' ' + 1);
    }
}

main();

